function custom_post_list_shortcode() {
    $terms = get_terms( array(
        'taxonomy' => 'topic',
        'hide_empty' => false,
    ) );
    $output = '';
    foreach ( $terms as $term ) {
        $output .= '<h2>' . $term->name . '</h2>';
        $args = array(
            'post_type' => 'policy',
            'posts_per_page' => 5,
            'tax_query' => array(
                array(
                    'taxonomy' => 'topic',
                    'field' => 'slug',
                    'terms' => $term->slug,
                ),
            ),
        );
        $query = new WP_Query( $args );
        if ( $query->have_posts() ) {
            $output .= '<ul>';
            while ( $query->have_posts() ) {
                $query->the_post();
                $output .= '<li><a href="' . get_the_permalink() . '">' . get_the_title() . '</a></li>';
            }
            wp_reset_postdata();
            $output .= '</ul>';
        } else {
            $output .= 'No policies found for this topic.';
        }
    }
    return $output;
}
add_shortcode( 'custom_post_list', 'custom_post_list_shortcode' );
